import React, { useState, useEffect, useRef } from 'react';
import Header from '../components/Header';
import MoviePlayer from '../components/MoviePlayer';
import ClipCard from '../components/ClipCard';
import { CLIPS, getMovie, likeClip, saveMovie, checkSaved } from '../services/api';
import { useAuth } from '../contexts/AuthContext';
import './Clips.css';

const Clips = () => {
  const { user } = useAuth();
  const [clips, setClips] = useState(CLIPS);
  const [selectedMovie, setSelectedMovie] = useState(null);
  const [savedStatus, setSavedStatus] = useState({});
  const containerRef = useRef(null);

  useEffect(() => {
    if (user) {
      // Загружаем статусы сохранения для каждого клипа
      clips.forEach(async (clip) => {
        const result = await checkSaved(clip.movie_id, user.email);
        setSavedStatus(prev => ({ ...prev, [clip.id]: result.saved }));
      });
    }
  }, [user, clips]);

  const handleLike = async (clipId) => {
    if (!user) {
      alert('Сначала надо зарегистрироваться, чтобы ставить лайки!');
      return;
    }

    const clip = clips.find(c => c.id === clipId);
    const isLiked = clip.liked || false;

    const result = await likeClip(clipId, !isLiked);

    if (result.success) {
      setClips(prev => prev.map(c => 
        c.id === clipId 
          ? { ...c, likes: result.likes, liked: !isLiked }
          : c
      ));
    }
  };

  const handleSave = async (clipId) => {
    if (!user) {
      alert('Сначала надо зарегистрироваться, чтобы сохранять фильмы!');
      return;
    }

    const clip = clips.find(c => c.id === clipId);
    const result = await saveMovie(clip.movie_id, user.email);

    if (result.success) {
      setSavedStatus(prev => ({ ...prev, [clipId]: result.saved }));
      alert(result.saved ? 'Фильм добавлен в отложенные!' : 'Фильм удален из отложенных');
    }
  };

  const handleOpenMovie = async (movieId) => {
    const movie = await getMovie(movieId);
    if (movie) {
      setSelectedMovie(movie);
    }
  };

  const handleClosePlayer = () => {
    setSelectedMovie(null);
  };

  return (
    <>
      <Header />
      <main className="clips-container" ref={containerRef}>
        {clips.map((clip, index) => (
          <ClipCard
            key={clip.id}
            clip={clip}
            index={index}
            isSaved={savedStatus[clip.id] || false}
            onLike={() => handleLike(clip.id)}
            onSave={() => handleSave(clip.id)}
            onOpenMovie={handleOpenMovie}
          />
        ))}
      </main>
      {selectedMovie && (
        <MoviePlayer movie={selectedMovie} onClose={handleClosePlayer} />
      )}
    </>
  );
};

export default Clips;
